#include <iostream>
#include <cmath>

using namespace std;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n;
    cin >> n;

    // For negative numbers, we consider absolute value? 
    // The problem says integer fits in int. Armstrong numbers are typically defined for non-negative.
    // But let's handle: if n < 0, it's definitely not an Armstrong number.
    if (n < 0) {
        cout << "NO\n";
        return 0;
    }

    // Count digits
    int temp = n;
    int digits = 0;
    while (temp > 0) {
        digits++;
        temp /= 10;
    }
    // Special case: n == 0
    if (n == 0) {
        digits = 1;  // 0 has 1 digit: 0^1 = 0, so YES
    }

    // Compute sum of digits raised to power 'digits'
    long long sum = 0;
    temp = n;
    while (temp > 0) {
        int d = temp % 10;
        long long p = 1;
        for (int i = 0; i < digits; i++) {
            p *= d;
        }
        sum += p;
        temp /= 10;
        // Early exit: if sum already exceeds n, it's not Armstrong
        if (sum > n) {
            cout << "NO\n";
            return 0;
        }
    }

    if (sum == n) {
        cout << "YES\n";
    } else {
        cout << "NO\n";
    }

    return 0;
}
